<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop Clone</title>
    <style>
        :root {
            --ubuntu-orange: #e95420;
            --ubuntu-aubergine: #300a24;
            --ubuntu-dark: #2c001e;
            --window-bg: #f2f2f2;
            --taskbar-bg: rgba(0, 0, 0, 0.6);
            --text-color: #333;
        }

        * { box-sizing: border-box; margin: 0; padding: 0; user-select: none; }

        body, html {
            width: 100%;
            height: 100%;
            overflow: hidden;
            font-family: 'Ubuntu', sans-serif, Arial, sans-serif;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: radial-gradient(circle, #5e2750 0%, #300a24 100%);
            position: relative;
            overflow: hidden;
        }

        /* Taskbar/Dock */
        #taskbar {
            position: absolute;
            bottom: 15px;
            left: 50%;
            transform: translateX(-50%);
            height: 50px;
            padding: 0 15px;
            background: var(--taskbar-bg);
            backdrop-filter: blur(10px);
            border-radius: 30px;
            display: flex;
            align-items: center;
            gap: 15px;
            z-index: 9999;
            border: 1px solid rgba(255,255,255,0.1);
        }

        .launcher-btn {
            width: 36px;
            height: 36px;
            background: rgba(255,255,255,0.1);
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: background 0.2s;
            font-size: 20px;
        }

        .launcher-btn:hover {
            background: var(--ubuntu-orange);
        }

        /* Window Styles */
        .window {
            position: absolute;
            min-width: 360px;
            min-height: 240px;
            background: var(--window-bg);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: flex;
            flex-direction: column;
            overflow: hidden;
            z-index: 10;
        }

        .win-header {
            background: #e0e0e0;
            padding: 8px 12px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: move;
            border-bottom: 1px solid #ccc;
        }

        .win-title {
            font-size: 14px;
            font-weight: bold;
            color: var(--text-color);
        }

        .win-controls {
            display: flex;
            gap: 8px;
        }

        .win-close {
            width: 14px;
            height: 14px;
            background: #ff5f56;
            border-radius: 50%;
            cursor: pointer;
            border: none;
        }

        .win-content {
            flex: 1;
            overflow: auto;
            position: relative;
        }

        /* Files App Styles */
        #files-path {
            padding: 8px;
            background: #ddd;
            font-size: 13px;
            font-family: monospace;
            border-bottom: 1px solid #ccc;
        }

        .files-toolbar {
            padding: 5px;
            border-bottom: 1px solid #ccc;
        }

        #files-up {
            cursor: pointer;
            padding: 2px 8px;
            background: #bbb;
            border: none;
            border-radius: 4px;
            font-size: 12px;
        }

        .fs-list {
            display: flex;
            flex-wrap: wrap;
            padding: 10px;
            gap: 15px;
        }

        .fs-item {
            width: 80px;
            display: flex;
            flex-direction: column;
            align-items: center;
            text-align: center;
            cursor: pointer;
            padding: 5px;
            border-radius: 4px;
        }

        .fs-item:hover {
            background: rgba(0,0,0,0.05);
        }

        .fs-icon {
            font-size: 32px;
            margin-bottom: 5px;
        }

        .fs-name {
            font-size: 12px;
            word-break: break-all;
            color: var(--text-color);
        }

        /* Notepad Styles */
        #tabs {
            display: flex;
            background: #ddd;
            padding: 5px 5px 0 5px;
            gap: 2px;
        }

        .tab {
            padding: 6px 12px;
            background: #bbb;
            border-radius: 5px 5px 0 0;
            font-size: 12px;
            cursor: pointer;
            max-width: 120px;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .tab.active {
            background: var(--window-bg);
        }

        #new-tab {
            padding: 4px 8px;
            cursor: pointer;
            font-weight: bold;
            border: none;
            background: transparent;
            font-size: 16px;
        }

        #editor {
            width: 100%;
            height: 100%;
            border: none;
            padding: 10px;
            resize: none;
            font-family: monospace;
            outline: none;
            background: var(--window-bg);
        }

    </style>
</head>
<body>

<div id="desktop">
    <!-- Taskbar -->
    <div id="taskbar">
        <div class="launcher-btn" id="open-files" title="Files">📁</div>
        <div class="launcher-btn" id="open-notepad" title="Notepad">📝</div>
    </div>

    <!-- Files Window Template (Hidden initially) -->
    <div id="files-window" class="window" style="display: none; top: 50px; left: 50px;">
        <div class="win-header">
            <span class="win-title">Files</span>
            <div class="win-controls"><button class="win-close"></button></div>
        </div>
        <div id="files-path">/</div>
        <div class="files-toolbar">
            <button id="files-up">UP</button>
        </div>
        <div class="win-content">
            <div class="fs-list" id="fs-list">
                <!-- Items injected here -->
            </div>
        </div>
    </div>

    <!-- Notepad Window Template (Hidden initially) -->
    <div id="notepad-window" class="window" style="display: none; top: 100px; left: 150px;">
        <div class="win-header">
            <span class="win-title">Notepad</span>
            <div class="win-controls"><button class="win-close"></button></div>
        </div>
        <div id="tabs">
            <!-- Tabs injected here -->
            <button id="new-tab">+</button>
        </div>
        <div class="win-content" style="display: flex; flex-wrap: wrap;">
            <textarea id="editor"></textarea>
        </div>
    </div>
</div>

<script>
    /** 
     * FILESYSTEM LOGIC
     */
    const filesystem = {
        '/': ['bin', 'etc', 'home', 'usr', 'var'],
        '/bin': [],
        '/etc': [],
        '/home': ['user'],
        '/home/user': ['Documents', 'Downloads', 'Pictures'],
        '/usr': [],
        '/var': [],
        '/home/user/Documents': [],
        '/home/user/Downloads': [],
        '/home/user/Pictures': []
    };

    let currentPath = '/';

    const fsListEl = document.getElementById('fs-list');
    const fsPathEl = document.getElementById('files-path');
    const filesUpBtn = document.getElementById('files-up');

    function renderFiles() {
        fsListEl.innerHTML = '';
        fsPathEl.textContent = currentPath;

        const items = filesystem[currentPath] || [];

        items.forEach(name => {
            const fullPath = currentPanelPath(currentPath, name);
            const isDir = filesystem[fullPath] !== undefined;

            const itemEl = document.createElement('div');
            itemEl.className = 'fs-item';
            itemEl.innerHTML = `
                <div class="fs-icon">${isDir ? '📁' : '📄'}</div>
                <div class="fs-name">${name}</div>
            `;

            itemEl.ondblclick = () => {
                if (isDir) {
                    currentPath = fullPath;
                    renderFiles();
                }
            };

            fsListEl.appendChild(itemEl);
        });
    }

    function currentPanelPath(base, name) {
        return base === '/' ? `/${name}` : `${base}/${name}`;
    }

    filesUpBtn.onclick = () => {
        if (currentPath === '/') return;
        const parts = currentPath.split('/').filter(p => p);
        parts.pop();
        currentPath = parts.length === 0 ? '/' : '/' + parts.join('/');
        renderFiles();
    };

    /**
     * NOTEPAD LOGIC (with Persistence)
     */
    let notepadState = {
        tabs: [{ id: Date.now(), title: 'Untitled', content: '' }],
        activeTabId: null
    };

    const tabsContainer = document.getElementById('tabs');
    const editor = document.app.editor || document.getElementById('editor'); // fallback check
    const newTabBtn = document.getElementById('new-tab');
    const editorEl = document.getElementById('editor');

    function loadNotepad() {
        const saved = localStorage.getItem('notepad_persistence');
        if (saved) {
            notepadState = JSON.parse(saved);
        } else {
            notepadState.activeTabId = notepadState.tabs[0].id;
        }
        renderTabs();
    }

    function saveNotepad() {
        localStorage.setItem('notepad_persistence', JSON.stringify(notepadState));
    }

    function renderTabs() {
        // Clear existing tabs (keep the + button)
        const buttons = tabsContainer.querySelectorAll('.tab');
        buttons.forEach(b => b.remove());

        notepadState.tabs.forEach(tab => {
            const tabEl = document.createElement('div');
            tabEl.className = `tab ${tab.id === notepadState.activeTabId ? 'active' : ''}`;
            tabEl.textContent = tab.title || 'Untitled';
            tabEl.onclick = () => {
                notepadState.activeTabId = tab.id;
                renderTabs();
                updateEditorContent();
            };
            tabsContainer.insertBefore(tabEl, newTabBtn);
        });

        updateEditorContent();
    }

    function updateEditorContent() {
        const activeTab = notepadState.tabs.find(t => t.id === notepadState.activeTabId);
        if (activeTab) {
            editorEl.value = activePanelText(activeTab.content); // helper logic below
            editorEl.value = activeTab.content;
        } else {
            editorEl.value = '';
        }
    }

    // Helper to handle text input
    editorEl.oninput = (e) => {
        const activeTab = notepadState.tabs.find(t => t.id === notepadState.activeTabId);
        if (activeTab) {
            activeTab.content = e.target.value;
            saveNotepad();
        }
    };

    newTabBtn.onclick = () => {
        const newId = Date.now();
        notepadState.tabs.push({ id: newId, title: 'Untitled', content: '' });
        notepadStatedActiveTabId = newId; // wait, logic error in variable name
        notepadState.activeTabId = newId;
        renderTabs();
        saveNotepad();
    };

    // Helper for text (not needed but clean)
    function activePanelText(txt) { return txt; }

    /**
     * WINDOW MANAGEMENT (Draggable & Close)
     */
    let zIndexCounter = 100;

    function setupWindow(winId) {
        const win = document.getElementById(winId);
        const header = win.querySelector('.win-header');
        const closeBtn = win.querySelector('.win-close');

        // Close functionality
        closeBtn.onclick = (e) => {
            e.stopPropagation();
            win.style.display = 'none';
        };

        // Bring to front on click
        win.onmousedown = () => {
            zIndexCounter++;
            win.style.zIndex = zIndexCounter;
        };

        // Dragging logic
        let isDragging = false;
        let offsetX, offsetY;

        header.onmousedown = (e) => {
            isDragging = true;
            offsetX = e.clientX - win.offsetLeft;
            offsetY = e.clientY - win.offsetTop;
            zIndexCounter++;
            win.style.zIndex = zIndexCounter;
        };

        document.onmousemove = (e) => {
            if (!isDragging) return;
            win.style.left = (e.clientX - offsetX) + 'px';
            win.style.top = (e.clientY - offsetY) + 'px';
        };

        document.onmouseup = () => {
            isDragging = false;
        };
    }

    // Launcher logic
    document.getElementById('open-files').onclick = () => {
        const win = document.getElementById('files-window');
        win.style.display = 'flex';
        win.style.zIndex = ++zIndexCounter;
        renderFiles();
    };

    document.getElementById('open-notepad').onclick = () => {
        const win = document.getElementById('notepad-window');
        win.style.display = 'flex';
        win.style.zIndex = ++zIndexCounter;
    };

    // Initialize everything
    window.onload = () => {
        setupWindow('files-window');
        setupWindow('notepad-window');
        renderFiles();
        loadNotepad();
    };

</script>
</body>
</html>
